diagnostics_hook:
#!/bin/bash
INPUT=$(head -c 65536); FILE=$(printf '%s' "$INPUT" | jq -r '.tool_input.file_path // ""')
[[ "$FILE" != *.cs ]] && { echo '{"decision":"approve"}'; exit 0; }
ERRORS=$(dotnet build --no-restore --nologo 2>&1 | grep -E 'error|warning' | head -10)
[ -n "$ERRORS" ] && echo "$ERRORS" >&2
echo '{"decision":"approve"}'
